import React, { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import { motion, useInView, useScroll, useTransform, animate } from 'framer-motion';
import { ArrowRight, Play, Zap, MessageCircle, Award, Users, Target, Salad, ShoppingBag, Dumbbell } from 'lucide-react';

const ADMIN_WHATSAPP = '919999999999';

/* ─── Animated counter hook ─────────────────────────────────────── */
function useCounter(target, duration = 1.6, inView) {
  const [val, setVal] = useState(0);
  const done = useRef(false);
  useEffect(() => {
    if (!inView || done.current) return;
    done.current = true;
    const ctrl = animate(0, target, {
      duration,
      ease: 'easeOut',
      onUpdate: v => setVal(Math.floor(v)),
    });
    return () => ctrl.stop();
  }, [inView, target, duration]);
  return val;
}

/* ─── SVG Cable-pulley machine ───────────────────────────────────── */
function CableMachine({ progress }) {
  // progress: 0..1  →  handle goes from top to bottom
  const handleY = 20 + progress * 110;
  const weightY = 130 - progress * 110;
  const ropeLen1 = handleY - 20;
  const ropeLen2 = 130 - weightY;

  return (
    <svg
      viewBox="0 0 160 220"
      className="w-full h-full"
      style={{ filter: 'drop-shadow(0 0 18px rgba(56,189,248,0.25))' }}
    >
      {/* Frame uprights */}
      <rect x="20" y="10" width="6" height="200" rx="3" fill="#1e3a4a" />
      <rect x="134" y="10" width="6" height="200" rx="3" fill="#1e3a4a" />
      {/* Top crossbar */}
      <rect x="20" y="10" width="120" height="6" rx="3" fill="#1e3a4a" />
      {/* Top pulley */}
      <circle cx="80" cy="17" r="9" fill="none" stroke="#38bdf8" strokeWidth="2.5" />
      <circle cx="80" cy="17" r="3.5" fill="#38bdf8" />

      {/* Rope from weight to pulley */}
      <line x1="80" y1="17" x2="80" y2={weightY} stroke="#64b5f6" strokeWidth="1.8" strokeDasharray="3 2" />
      {/* Rope from pulley to handle */}
      <line x1="80" y1="17" x2="80" y2={handleY} stroke="#64b5f6" strokeWidth="1.8" strokeDasharray="3 2" />

      {/* Weight stack */}
      {[0, 1, 2, 3].map(i => (
        <rect
          key={i}
          x="62"
          y={weightY - i * 8}
          width="36"
          height="7"
          rx="2"
          fill={i === 0 ? '#38bdf8' : '#1a3a4f'}
          stroke="#38bdf8"
          strokeWidth="0.8"
          opacity={i === 0 ? 1 : 0.7 - i * 0.1}
        />
      ))}
      {/* Weight pin */}
      <rect x="78" y={weightY - 30} width="4" height="35" rx="2" fill="#64b5f6" opacity="0.6" />

      {/* Handle / bar */}
      <rect x="55" y={handleY} width="50" height="7" rx="3.5" fill="#90caf9" />
      {/* Hand grips */}
      <rect x="55" y={handleY - 2} width="12" height="11" rx="3" fill="#38bdf8" opacity="0.6" />
      <rect x="93" y={handleY - 2} width="12" height="11" rx="3" fill="#38bdf8" opacity="0.6" />

      {/* Bottom base */}
      <rect x="14" y="205" width="132" height="8" rx="4" fill="#1e3a4a" />
    </svg>
  );
}

/* ─── Animated barbell (hero decoration) ────────────────────────── */
function FloatingBarbell({ delay = 0, scale = 1, opacity = 0.15 }) {
  return (
    <motion.div
      style={{ opacity, scale, position: 'absolute', pointerEvents: 'none' }}
      animate={{ y: [0, -18, 0], rotate: [0, 3, 0] }}
      transition={{ duration: 4 + delay, repeat: Infinity, ease: 'easeInOut', delay }}
    >
      <svg width="120" height="28" viewBox="0 0 120 28" fill="none">
        {/* Bar */}
        <rect x="22" y="11" width="76" height="6" rx="3" fill="#38bdf8" opacity="0.8" />
        {/* Left plates */}
        <rect x="8"  y="4"  width="14" height="20" rx="3" fill="#1565c0" />
        <rect x="3"  y="7"  width="7"  height="14" rx="2" fill="#0d47a1" />
        {/* Right plates */}
        <rect x="98"  y="4"  width="14" height="20" rx="3" fill="#1565c0" />
        <rect x="110" y="7"  width="7"  height="14" rx="2" fill="#0d47a1" />
      </svg>
    </motion.div>
  );
}

/* ─── Stat card with counter ─────────────────────────────────────── */
function StatCard({ value, label, suffix = '+', delay = 0 }) {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: '-60px' });
  const num = useCounter(parseInt(value), 1.8, inView);
  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, y: 30 }}
      animate={inView ? { opacity: 1, y: 0 } : {}}
      transition={{ duration: 0.6, delay }}
      className="text-center"
    >
      <div className="gym-font text-5xl md:text-6xl gradient-text mb-1">
        {num}{suffix}
      </div>
      <div className="text-gray-400 text-sm tracking-wide">{label}</div>
    </motion.div>
  );
}

/* ─── Scroll-triggered cable section ────────────────────────────── */
function CableSection() {
  const ref = useRef(null);
  const { scrollYProgress } = useScroll({ target: ref, offset: ['start end', 'end start'] });
  const progress = useTransform(scrollYProgress, [0.1, 0.7], [0, 1]);
  const [prog, setProg] = useState(0);
  useEffect(() => progress.on('change', v => setProg(v)), [progress]);

  const textPoints = [
    { p: 0.1,  text: 'Set your goal' },
    { p: 0.35, text: 'Build the habit' },
    { p: 0.6,  text: 'Earn the result' },
  ];

  return (
    <section ref={ref} className="relative py-10" style={{ minHeight: '520px' }}>
      <div className="max-w-5xl mx-auto px-6">
        <div className="text-center mb-10">
          <motion.h2
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6 }}
            className="gym-font text-5xl text-white"
          >
            THE PULL TO <span className="gradient-text">GREATNESS</span>
          </motion.h2>
          <motion.p
            initial={{ opacity: 0 }}
            whileInView={{ opacity: 1 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6, delay: 0.2 }}
            className="text-gray-400 mt-3"
          >
            Scroll to work the machine — every rep counts
          </motion.p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
          {/* Machine */}
          <div className="h-64 max-w-xs mx-auto w-full">
            <CableMachine progress={prog} />
          </div>

          {/* Story text that fades in at each milestone */}
          <div className="space-y-8">
            {textPoints.map((tp, i) => (
              <motion.div
                key={i}
                animate={{
                  opacity: prog >= tp.p ? 1 : 0.15,
                  x: prog >= tp.p ? 0 : 20,
                }}
                transition={{ duration: 0.4 }}
                className="flex items-start gap-4"
              >
                <div
                  className="w-10 h-10 rounded-full border-2 flex-shrink-0 flex items-center justify-center font-bold text-sm transition-all duration-500"
                  style={{
                    borderColor: prog >= tp.p ? '#38bdf8' : '#1e3a4a',
                    background:  prog >= tp.p ? 'rgba(56,189,248,0.15)' : 'transparent',
                    color:       prog >= tp.p ? '#38bdf8' : '#334155',
                  }}
                >
                  {i + 1}
                </div>
                <div>
                  <div className="text-white font-bold text-lg">{tp.text}</div>
                  <div className="text-gray-500 text-sm mt-1">
                    {['Define what you want. Write it. Own it.',
                      'Show up every single day, no excuses.',
                      'Transformation belongs to those who persist.'][i]}
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

/* ─── Features ───────────────────────────────────────────────────── */
const features = [
  { icon: <Dumbbell className="w-6 h-6 text-sky-400" />,    title: 'Expert Workouts',    desc: 'Category-wise exercises for every muscle group with video guidance' },
  { icon: <Salad className="w-6 h-6 text-green-400" />,     title: 'Personalized Diet',  desc: 'Custom meal plans tailored to your fitness goals by expert trainers' },
  { icon: <ShoppingBag className="w-6 h-6 text-indigo-400" />, title: 'Supplement Store', desc: 'Premium quality supplements — protein, creatine, vitamins & more' },
  { icon: <Zap className="w-6 h-6 text-yellow-400" />,      title: 'Auto Reminders',     desc: 'Never miss a fee — automatic WhatsApp & website notifications' },
  { icon: <Target className="w-6 h-6 text-cyan-400" />,     title: 'Progress Tracking',  desc: 'Visual before/after transformations and body progress charts' },
  { icon: <Users className="w-6 h-6 text-sky-300" />,       title: 'Expert Trainers',    desc: 'Certified trainers to guide you every step of the fitness journey' },
];

/* ─── Muscle groups ──────────────────────────────────────────────── */
const muscleGroups = [
  { name: 'Chest',     img: 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?w=400&q=80' },
  { name: 'Back',      img: 'https://images.unsplash.com/photo-1603287681836-b174ce5074c2?w=400&q=80' },
  { name: 'Shoulders', img: 'https://images.unsplash.com/photo-1532029837206-abbe2b7620e3?w=400&q=80' },
  { name: 'Arms',      img: 'https://images.unsplash.com/photo-1581009137042-c552e485697a?w=400&q=80' },
  { name: 'Legs',      img: 'https://images.unsplash.com/photo-1434608519344-49d77a699e1d?w=400&q=80' },
  { name: 'Core',      img: 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&q=80' },
  { name: 'Cardio',    img: 'https://images.unsplash.com/photo-1538805060514-97d9cc17730c?w=400&q=80' },
  { name: 'Full Body', img: 'https://images.unsplash.com/photo-1517836357463-d25dfeac3438?w=400&q=80' },
];

/* ─── Horizontal marquee strip ───────────────────────────────────── */
function MarqueeStrip() {
  const items = ['STRENGTH', 'ENDURANCE', 'NUTRITION', 'MUSCLE', 'CARDIO', 'TRANSFORM', 'DISCIPLINE', 'FOCUS', 'PROGRESS'];
  return (
    <div className="overflow-hidden py-4 border-y border-white/5 bg-[#050810]" style={{ maskImage: 'linear-gradient(to right, transparent, black 10%, black 90%, transparent)' }}>
      <motion.div
        className="flex gap-10 whitespace-nowrap"
        animate={{ x: ['0%', '-50%'] }}
        transition={{ duration: 22, repeat: Infinity, ease: 'linear' }}
      >
        {[...items, ...items].map((t, i) => (
          <span key={i} className="gym-font text-2xl text-white/10 tracking-widest flex-shrink-0 select-none">
            {t} <span className="text-sky-500/30 mx-2">·</span>
          </span>
        ))}
      </motion.div>
    </div>
  );
}

/* ─── Main component ─────────────────────────────────────────────── */
export default function HomePage() {
  return (
    <div className="min-h-screen bg-[#0a0a0f] overflow-x-hidden">

      {/* ── HERO ─────────────────────────────────────────────────── */}
      <section className="relative min-h-screen flex items-center justify-center bg-grid overflow-hidden">
        {/* Ambient blobs */}
        <div className="absolute inset-0 bg-gradient-to-br from-blue-950/60 via-transparent to-sky-950/40" />
        <motion.div
          className="absolute top-24 left-10 w-72 h-72 bg-sky-600/10 rounded-full blur-3xl"
          animate={{ scale: [1, 1.2, 1], opacity: [0.6, 1, 0.6] }}
          transition={{ duration: 7, repeat: Infinity, ease: 'easeInOut' }}
        />
        <motion.div
          className="absolute bottom-24 right-10 w-96 h-96 bg-blue-700/10 rounded-full blur-3xl"
          animate={{ scale: [1.1, 0.9, 1.1], opacity: [0.5, 0.9, 0.5] }}
          transition={{ duration: 9, repeat: Infinity, ease: 'easeInOut', delay: 2 }}
        />

        {/* Floating barbells */}
        <div className="absolute top-32 right-24 hidden lg:block">
          <FloatingBarbell delay={0}   scale={0.8} opacity={0.18} />
        </div>
        <div className="absolute bottom-40 left-16 hidden lg:block">
          <FloatingBarbell delay={1.5} scale={1.1} opacity={0.12} />
        </div>
        <div className="absolute top-1/2 right-8 hidden xl:block">
          <FloatingBarbell delay={3}   scale={0.6} opacity={0.1} />
        </div>

        <div className="relative z-10 text-center px-4 max-w-5xl mx-auto">
          {/* Badge */}
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="inline-flex items-center gap-2 bg-sky-500/10 border border-sky-500/20 rounded-full px-5 py-2 text-sky-400 text-sm mb-8"
          >
            <motion.span
              animate={{ rotate: [0, 15, -15, 0] }}
              transition={{ duration: 2, repeat: Infinity, delay: 2 }}
            >
              <Zap size={14} />
            </motion.span>
            Welcome to FitNation By Ajeet — Uniting a Healthier World
          </motion.div>

          {/* Headline — letters stagger in */}
          <div className="overflow-hidden mb-2">
            <motion.h1
              initial={{ y: 120, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
              className="gym-font text-7xl sm:text-8xl md:text-9xl text-white leading-none"
            >
              UNITE YOUR
            </motion.h1>
          </div>
          <div className="overflow-hidden mb-8">
            <motion.h1
              initial={{ y: 120, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1], delay: 0.12 }}
              className="gym-font text-7xl sm:text-8xl md:text-9xl leading-none gradient-text"
            >
              FITNESS
            </motion.h1>
          </div>

          {/* Sub-text */}
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.7, delay: 0.4 }}
            className="text-gray-400 text-lg md:text-xl max-w-2xl mx-auto mb-10"
          >
            Elite training, nutrition mastery &amp; premium supplements.
            Join FitNation By Ajeet and unleash the champion within you.
          </motion.p>

          {/* CTA buttons */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.6 }}
            className="flex flex-col sm:flex-row gap-4 justify-center items-center"
          >
            <Link to="/enquiry" className="btn-fire flex items-center gap-2 text-base px-9 py-4">
              Start Your Journey <ArrowRight size={18} />
            </Link>
            <Link
              to="/exercises"
              className="flex items-center gap-2 text-white border border-white/15 rounded-lg px-9 py-4 hover:border-sky-500/50 hover:bg-sky-500/5 transition-all text-base"
            >
              <Play size={18} className="text-sky-400" /> Explore Workouts
            </Link>
            <a
              href={`https://wa.me/${ADMIN_WHATSAPP}?text=Hi!%20I'm%20interested%20in%20joining%20FitNation%20By%20Ajeet`}
              target="_blank" rel="noreferrer"
              className="flex items-center gap-2 text-white bg-green-700/80 hover:bg-green-600 border border-green-600/30 rounded-lg px-9 py-4 transition-all text-base"
            >
              <MessageCircle size={18} /> WhatsApp Us
            </a>
          </motion.div>
        </div>

        {/* Scroll cue */}
        <motion.div
          className="absolute bottom-8 left-1/2 -translate-x-1/2 flex flex-col items-center gap-2"
          animate={{ y: [0, 8, 0] }}
          transition={{ duration: 2, repeat: Infinity, ease: 'easeInOut' }}
        >
          <div className="w-[1px] h-10 bg-gradient-to-b from-transparent via-sky-400/60 to-transparent" />
          <span className="text-gray-600 text-xs tracking-widest uppercase">Scroll</span>
        </motion.div>
      </section>

      {/* ── MARQUEE ───────────────────────────────────────────────── */}
      <MarqueeStrip />

      {/* ── STATS with counting numbers ───────────────────────────── */}
      <section className="py-20 border-b border-white/5">
        <div className="max-w-5xl mx-auto px-6 grid grid-cols-2 md:grid-cols-4 gap-10">
          <StatCard value="500" label="Active Members"    delay={0}   />
          <StatCard value="50"  label="Expert Programs"   delay={0.1} />
          <StatCard value="10"  label="Years Experience"  delay={0.2} />
          <StatCard value="200" label="Transformations"   delay={0.3} />
        </div>
      </section>

      {/* ── CABLE MACHINE (scroll animation) ─────────────────────── */}
      <section className="py-6 border-b border-white/5 bg-[#050810]">
        <CableSection />
      </section>

      {/* ── FEATURES ─────────────────────────────────────────────── */}
      <section className="py-28 px-6">
        <div className="max-w-7xl mx-auto">
          <div className="text-center mb-16">
            <motion.h2
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6 }}
              className="gym-font text-5xl text-white mb-3"
            >
              EVERYTHING YOU <span className="gradient-text">NEED</span>
            </motion.h2>
            <motion.p
              initial={{ opacity: 0 }}
              whileInView={{ opacity: 1 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6, delay: 0.2 }}
              className="text-gray-400 text-lg"
            >
              One platform. Total fitness transformation.
            </motion.p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
            {features.map((f, i) => (
              <motion.div
                key={i}
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ delay: i * 0.08, duration: 0.5 }}
                whileHover={{ y: -4 }}
                className="glass rounded-xl p-6 border border-white/5 hover:border-sky-500/20 transition-colors group cursor-default"
              >
                <div className="w-11 h-11 rounded-xl bg-sky-500/8 border border-white/5 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform duration-300">
                  {f.icon}
                </div>
                <h3 className="text-white font-semibold text-lg mb-2">{f.title}</h3>
                <p className="text-gray-500 text-sm leading-relaxed">{f.desc}</p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* ── MUSCLE GROUPS — horizontal slide-in cards ─────────────── */}
      <section className="py-28 px-6 bg-[#050810] border-y border-white/5">
        <div className="max-w-7xl mx-auto">
          <div className="text-center mb-14">
            <motion.h2
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6 }}
              className="gym-font text-5xl text-white mb-3"
            >
              TRAIN BY <span className="gradient-text">MUSCLE GROUP</span>
            </motion.h2>
            <motion.p
              initial={{ opacity: 0 }}
              whileInView={{ opacity: 1 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6, delay: 0.15 }}
              className="text-gray-400 text-lg"
            >
              Targeted exercises for every major muscle group
            </motion.p>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
            {muscleGroups.map((m, i) => {
              const fromLeft = i % 2 === 0;
              return (
                <motion.div
                  key={i}
                  initial={{ opacity: 0, x: fromLeft ? -40 : 40 }}
                  whileInView={{ opacity: 1, x: 0 }}
                  viewport={{ once: true, margin: '-40px' }}
                  transition={{ duration: 0.55, delay: i * 0.06, ease: [0.25, 0.46, 0.45, 0.94] }}
                  whileHover={{ scale: 1.04 }}
                >
                  <Link
                    to={`/exercises?muscle=${m.name.toLowerCase().replace(' ', '-')}`}
                    className="relative block rounded-xl overflow-hidden h-40 border border-white/8 group cursor-pointer"
                  >
                    <img
                      src={m.img}
                      alt={m.name}
                      loading="lazy"
                      className="absolute inset-0 w-full h-full object-cover opacity-35 group-hover:opacity-55 group-hover:scale-105 transition-all duration-500"
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent" />
                    {/* Glowing bottom line on hover */}
                    <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-gradient-to-r from-transparent via-sky-400 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                    <div className="absolute bottom-0 left-0 right-0 p-3">
                      <div className="text-white font-bold text-sm tracking-wide">{m.name}</div>
                    </div>
                  </Link>
                </motion.div>
              );
            })}
          </div>

          <motion.div
            initial={{ opacity: 0, y: 10 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.5, delay: 0.4 }}
            className="text-center mt-10"
          >
            <Link to="/exercises" className="btn-fire inline-flex items-center gap-2 px-8 py-3">
              View All Exercises <ArrowRight size={16} />
            </Link>
          </motion.div>
        </div>
      </section>

      {/* ── CTA BANNER ───────────────────────────────────────────── */}
      <section className="py-28 px-6">
        <div className="max-w-4xl mx-auto">
          <motion.div
            initial={{ opacity: 0, scale: 0.97 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
            transition={{ duration: 0.7 }}
            className="relative rounded-2xl overflow-hidden border border-sky-500/15 p-10 md:p-16 text-center"
            style={{ background: 'linear-gradient(135deg, rgba(33,150,243,0.08) 0%, rgba(13,27,42,0.9) 60%)' }}
          >
            {/* Subtle animated ring */}
            <motion.div
              className="absolute -top-20 -right-20 w-80 h-80 rounded-full border border-sky-500/10"
              animate={{ rotate: 360 }}
              transition={{ duration: 30, repeat: Infinity, ease: 'linear' }}
            />
            <motion.div
              className="absolute -bottom-16 -left-16 w-60 h-60 rounded-full border border-sky-500/8"
              animate={{ rotate: -360 }}
              transition={{ duration: 25, repeat: Infinity, ease: 'linear' }}
            />

            <Award size={48} className="text-sky-400 mx-auto mb-5" />
            <h2 className="gym-font text-5xl text-white mb-4">
              READY TO <span className="gradient-text">CRUSH IT?</span>
            </h2>
            <p className="text-gray-400 text-lg mb-10 max-w-xl mx-auto">
              Join hundreds of members who united their fitness with FitNation By Ajeet
            </p>
            <div className="flex flex-col sm:flex-row gap-4 justify-center">
              <Link to="/enquiry" className="btn-fire text-lg px-10 py-4">
                Join Now
              </Link>
